    'hero.badge': 'Principal Software Engineer | AI Specialist | Cloud Infrastructure & AWS Expert',
    'hero.h1Line1': 'Build with rigor.',
    'hero.h1Line2': 'Ship what lasts.',
    'hero.sub': 'Full-Stack TypeScript developer: Node, Angular, React, and React Native. AWS infrastructure, AI-Driven apps, Spec-Driven Development, and TDD.',
    'hero.yearsBuilding': 'Years building',
