    'workflow.build.label': 'How I ship',
    'workflow.build.heading': 'Ship products that work,\nand keep working.',
    'workflow.build.body': "Good software rarely comes from clever abstractions. It comes from the dull work of clear boundaries, typed contracts, and tests that run. I build for whoever touches the code two years from now, not for today's excitement.",
    'workflow.build.cta': "See what I've built",
    'workflow.write.label': 'The writing',
    'workflow.write.heading': 'Write to think.\nPublish to share.',
    'workflow.write.body': "Writing is how I find out what I actually understand. I publish long pieces on tooling, architecture decisions, and the tradeoffs that don't fit in a tweet. If one post saves you an afternoon of debugging, that's enough.",
    'workflow.write.cta': 'Read the blog',
    'workflow.opensource.label': 'Coding time',
    'workflow.opensource.heading': 'Code every day.\nTracked since January 2026.',
    'workflow.opensource.body': 'Hours measured, not guessed. WakaTime logs all of it on its own: languages, projects, editors. The history starts in January 2026, when I began tracking.',
    'workflow.opensource.addendum': "Before that I'd been coding since 2020, just not measuring. At 8h a weekday, that's roughly 12,480 hours.",
    'workflow.opensource.cta': 'View WakaTime',

    'projects.label': 'Open source',
